SELECT name, capacity_factor
FROM generators
WHERE capacity_factor = (SELECT MAX(capacity_factor) FROM generators);

SELECT MAX(last_maintenance_date) AS last_maintenance_date 
FROM generators 
WHERE operating_status != 'maintenance';

SELECT name, type, max_power 
FROM generators
WHERE max_power = (
  SELECT MAX(max_power) 
  FROM generators
);

SELECT generator_id, MAX(efficiency) AS peak_efficiency
FROM performance_metrics
GROUP BY generator_id;

SELECT name 
FROM generators 
WHERE max_power >= 200;

SELECT marginal_cost
FROM cost_metrics
WHERE generator_id = 1;

SELECT MAX(max_power) 
FROM generators 
WHERE bus_id = 1;
